 1	import * as React from 'react';
 2	import { Text } from '@patternfly/react-core';
 3	import { useTranslation, Trans } from 'react-i18next';
 4	import { ExternalLink } from '../utils/link';
 5	import { ConfigMapKind } from './types';
 6	
 7	type GithubSectionProps = {
 8	  pac: ConfigMapKind;
 9	};
10	
11	const GithubSection: React.FC<GithubSectionProps> = ({ pac }) => {
12	  const { t } = useTranslation('plugin__pipelines-console-plugin');
13	  const appLink = pac?.data?.['app-link'] ?? '';
14	  return (
15	    <Text>
16	      <Trans t={t} ns="plugin__pipelines-console-plugin">
17	        Use <ExternalLink href={appLink}>{appLink}</ExternalLink> link to
18	        install the GitHub Application to your repositories in your
19	        organisation/account.
20	      </Trans>
21	    </Text>
22	  );
23	};
24	
25	export default GithubSection;

